/* ASN1T_NeighborCell_Item */

ASN1T_NeighborCell_Item* new_ASN1T_NeighborCell_Item (ASN1CType& ccobj)
{
   void* pdata = ccobj.memAlloc (sizeof(ASN1T_NeighborCell_Item));
   if (0 == pdata) return 0;
   else return new (pdata) ASN1T_NeighborCell_Item;
}

int asn1Init_NeighborCell_Item (ASN1T_NeighborCell_Item* pvalue, 
   OSBOOL free, OSCTXT *pctxt)
{
   if (0 == pvalue) return RTERR_NULLPTR;
   if (free) {
      asn1Free_NeighborCell_Item (pctxt, pvalue);
   }
   else {
      pvalue->t = 0;
      OSCRTLMEMSET (&pvalue->u, 0, sizeof(pvalue->u));
   }
   return 0;
}

void asn1Free_NeighborCell_Item (OSCTXT *pctxt, 
   ASN1T_NeighborCell_Item* pvalue)
{
   if (0 == pvalue) return;
   switch (pvalue->t) {
      case 0: break; /* no choice; nothing to free */
      case 1:
         if (0 != pvalue->u.ranType_Choice_NR) {
            asn1Free_NeighborCell_Item_Choice_NR (pctxt, pvalue->u.ranType_Choice_NR);
            rtxMemFreePtr (pctxt, (void*)pvalue->u.ranType_Choice_NR);
            pvalue->u.ranType_Choice_NR = 0;
         }
         break;

      case 2:
         if (0 != pvalue->u.ranType_Choice_EUTRA) {
            asn1Free_NeighborCell_Item_Choice_E_UTRA (pctxt, pvalue->u.ranType_Choice_EUTRA);
            rtxMemFreePtr (pctxt, (void*)pvalue->u.ranType_Choice_EUTRA);
            pvalue->u.ranType_Choice_EUTRA = 0;
         }
         break;

      default:
         if (0 != pvalue->u.extElem1) {
            if (!rtxCtxtTestFlag (pctxt, ASN1FASTCOPY)) {
               rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1->data);
               pvalue->u.extElem1->data = 0;
            }
            rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1);
            pvalue->u.extElem1 = 0;
         }
   }
}

