/* ASN1T_RANParameter_Value */

ASN1T_RANParameter_Value* new_ASN1T_RANParameter_Value (ASN1CType& ccobj)
{
   void* pdata = ccobj.memAlloc (sizeof(ASN1T_RANParameter_Value));
   if (0 == pdata) return 0;
   else return new (pdata) ASN1T_RANParameter_Value;
}

int asn1Init_RANParameter_Value (ASN1T_RANParameter_Value* pvalue, 
   OSBOOL free, OSCTXT *pctxt)
{
   if (0 == pvalue) return RTERR_NULLPTR;
   if (free) {
      asn1Free_RANParameter_Value (pctxt, pvalue);
   }
   else {
      pvalue->t = 0;
      OSCRTLMEMSET (&pvalue->u, 0, sizeof(pvalue->u));
   }
   return 0;
}

void asn1Free_RANParameter_Value (OSCTXT *pctxt, 
   ASN1T_RANParameter_Value* pvalue)
{
   if (0 == pvalue) return;
   switch (pvalue->t) {
      case 0: break; /* no choice; nothing to free */
      case 1:
         break;

      case 2:
         break;

      case 3:
         break;

      case 4:
         if (0 != pvalue->u.valueBitS) {
            if (pvalue->u.valueBitS->numbits > 0) {
               rtxMemFreePtr (pctxt, (void*)pvalue->u.valueBitS->data);
               pvalue->u.valueBitS->numbits = 0;
               pvalue->u.valueBitS->data = 0;
            }
            rtxMemFreePtr (pctxt, (void*)pvalue->u.valueBitS);
            pvalue->u.valueBitS = 0;
         }
         break;

      case 5:
         if (0 != pvalue->u.valueOctS) {
            if (pvalue->u.valueOctS->numocts > 0) {
               rtxMemFreePtr (pctxt, (void*)pvalue->u.valueOctS->data);
               pvalue->u.valueOctS->numocts = 0;
               pvalue->u.valueOctS->data = 0;
            }
            rtxMemFreePtr (pctxt, (void*)pvalue->u.valueOctS);
            pvalue->u.valueOctS = 0;
         }
         break;

      case 6:
         rtxMemFreePtr (pctxt, (void*)pvalue->u.valuePrintableString);
         pvalue->u.valuePrintableString = 0;
         break;

      default:
         if (0 != pvalue->u.extElem1) {
            if (!rtxCtxtTestFlag (pctxt, ASN1FASTCOPY)) {
               rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1->data);
               pvalue->u.extElem1->data = 0;
            }
            rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1);
            pvalue->u.extElem1 = 0;
         }
   }
}

