/* ASN1T_RANParameter_ValueType */

ASN1T_RANParameter_ValueType* 
   new_ASN1T_RANParameter_ValueType (ASN1CType& ccobj)
{
   void* pdata = ccobj.memAlloc (sizeof(ASN1T_RANParameter_ValueType));
   if (0 == pdata) return 0;
   else return new (pdata) ASN1T_RANParameter_ValueType;
}

int asn1Init_RANParameter_ValueType (ASN1T_RANParameter_ValueType* pvalue, 
   OSBOOL free, OSCTXT *pctxt)
{
   if (0 == pvalue) return RTERR_NULLPTR;
   if (free) {
      asn1Free_RANParameter_ValueType (pctxt, pvalue);
   }
   else {
      pvalue->t = 0;
      OSCRTLMEMSET (&pvalue->u, 0, sizeof(pvalue->u));
   }
   return 0;
}

void asn1Free_RANParameter_ValueType (OSCTXT *pctxt, 
   ASN1T_RANParameter_ValueType* pvalue)
{
   if (0 == pvalue) return;
   switch (pvalue->t) {
      case 0: break; /* no choice; nothing to free */
      case 1:
         if (0 != pvalue->u.ranP_Choice_ElementTrue) {
            asn1Free_RANParameter_ValueType_Choice_ElementTrue (pctxt, pvalue->u.ranP_Choice_ElementTrue);
            rtxMemFreePtr (pctxt, (void*)pvalue->u.ranP_Choice_ElementTrue);
            pvalue->u.ranP_Choice_ElementTrue = 0;
         }
         break;

      case 2:
         if (0 != pvalue->u.ranP_Choice_ElementFalse) {
            asn1Free_RANParameter_ValueType_Choice_ElementFalse (pctxt, pvalue->u.ranP_Choice_ElementFalse);
            rtxMemFreePtr (pctxt, (void*)pvalue->u.ranP_Choice_ElementFalse);
            pvalue->u.ranP_Choice_ElementFalse = 0;
         }
         break;

      case 3:
         if (0 != pvalue->u.ranP_Choice_Structure) {
            asn1Free_RANParameter_ValueType_Choice_Structure (pctxt, pvalue->u.ranP_Choice_Structure);
            rtxMemFreePtr (pctxt, (void*)pvalue->u.ranP_Choice_Structure);
            pvalue->u.ranP_Choice_Structure = 0;
         }
         break;

      case 4:
         if (0 != pvalue->u.ranP_Choice_List) {
            asn1Free_RANParameter_ValueType_Choice_List (pctxt, pvalue->u.ranP_Choice_List);
            rtxMemFreePtr (pctxt, (void*)pvalue->u.ranP_Choice_List);
            pvalue->u.ranP_Choice_List = 0;
         }
         break;

      default:
         if (0 != pvalue->u.extElem1) {
            if (!rtxCtxtTestFlag (pctxt, ASN1FASTCOPY)) {
               rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1->data);
               pvalue->u.extElem1->data = 0;
            }
            rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1);
            pvalue->u.extElem1 = 0;
         }
   }
}

