/* ASN1T_MessageType_Choice */

ASN1T_MessageType_Choice* new_ASN1T_MessageType_Choice (ASN1CType& ccobj)
{
   void* pdata = ccobj.memAlloc (sizeof(ASN1T_MessageType_Choice));
   if (0 == pdata) return 0;
   else return new (pdata) ASN1T_MessageType_Choice;
}

int asn1Init_MessageType_Choice (ASN1T_MessageType_Choice* pvalue, 
   OSBOOL free, OSCTXT *pctxt)
{
   if (0 == pvalue) return RTERR_NULLPTR;
   if (free) {
      asn1Free_MessageType_Choice (pctxt, pvalue);
   }
   else {
      pvalue->t = 0;
      OSCRTLMEMSET (&pvalue->u, 0, sizeof(pvalue->u));
   }
   return 0;
}

void asn1Free_MessageType_Choice (OSCTXT *pctxt, 
   ASN1T_MessageType_Choice* pvalue)
{
   if (0 == pvalue) return;
   switch (pvalue->t) {
      case 0: break; /* no choice; nothing to free */
      case 1:
         if (0 != pvalue->u.messageType_Choice_NI) {
            asn1Free_MessageType_Choice_NI (pctxt, pvalue->u.messageType_Choice_NI);
            rtxMemFreePtr (pctxt, (void*)pvalue->u.messageType_Choice_NI);
            pvalue->u.messageType_Choice_NI = 0;
         }
         break;

      case 2:
         if (0 != pvalue->u.messageType_Choice_RRC) {
            asn1Free_MessageType_Choice_RRC (pctxt, pvalue->u.messageType_Choice_RRC);
            rtxMemFreePtr (pctxt, (void*)pvalue->u.messageType_Choice_RRC);
            pvalue->u.messageType_Choice_RRC = 0;
         }
         break;

      default:
         if (0 != pvalue->u.extElem1) {
            if (!rtxCtxtTestFlag (pctxt, ASN1FASTCOPY)) {
               rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1->data);
               pvalue->u.extElem1->data = 0;
            }
            rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1);
            pvalue->u.extElem1 = 0;
         }
   }
}

